class Solution:
    def resultArray(self, nums, k):
        res = [0] * k
        ending = [0] * k
        for v in nums:
            r = v % k
            nxt = [0] * k
            nxt[r] += 1
            for rem in range(k):
                if ending[rem]:
                    nxt[(rem * r) % k] += ending[rem]
            for rem in range(k):
                res[rem] += nxt[rem]
            ending = nxt
        return res

