var resultArray = function(nums, k) {
    const res = new Array(k).fill(0);
    let ending = new Array(k).fill(0);
    for (const v of nums) {
        const r = ((v % k) + k) % k;
        const nxt = new Array(k).fill(0);
        nxt[r] += 1;
        for (let rem = 0; rem < k; rem++) {
            if (ending[rem]) nxt[(rem * r) % k] += ending[rem];
        }
        for (let rem = 0; rem < k; rem++) res[rem] += nxt[rem];
        ending = nxt;
    }
    return res;
};
